import { Input as InputPrimitive } from "@base-ui/react/input";
import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import * as stylex from "@stylexjs/stylex";
import type * as React from "react";
import { useId } from "react";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { inputStyles } from "./input.styles";

type InputSize = "sm" | "default" | "lg";
type _BaseInputProps = Omit<
	InputPrimitive.Props & React.RefAttributes<HTMLInputElement>,
	"size"
>;
export type InputProps = PropsWithStylex<_BaseInputProps> & {
	size?: InputSize;
	error?: string;
	wrapperStyle?: stylex.StyleXStyles;
};

type LabelProps = PropsWithStylex<useRender.ComponentProps<"label">> & {
	style?: stylex.StyleXStyles;
};

export function Label({
	render,
	style,
	...props
}: LabelProps): React.ReactElement {
	const defaultProps = {
		...stylex.props(inputStyles.label, style),
		"data-slot": "label",
	};

	return useRender({
		defaultTagName: "label",
		props: mergeProps<"label">(defaultProps, props),
		render,
	});
}

export function Input({
	error,
	style,
	size = "default",
	...props
}: InputProps) {
	const generatedId = useId();
	const fieldId = props.id ?? generatedId;

	return (
		<InputPrimitive
			id={fieldId}
			data-slot="input"
			{...stylex.props(
				inputStyles.input,
				size === "sm" && inputStyles.inputSm,
				size === "lg" && inputStyles.inputLg,
				error ? inputStyles.inputError : null,
				style,
			)}
			{...props}
		/>
	);
}

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { spacing } from "@/lib/theme/tokens.stylex";

export const inputStyles = stylex.create({
	label: {
		fontSize: 14,
		display: "inline-flex",
		gap: 4,
		lineHeight: 1.4,
		fontWeight: 400,
		color: theme.contentSecondary,
	},

	labelSm: {
		fontSize: 13,
	},

	labelLg: {
		fontSize: 15,
	},

	input: {
		width: "100%",
		boxSizing: "border-box",
		paddingTop: spacing.small,
		paddingBottom: spacing.small,
		paddingLeft: spacing.medium,
		paddingRight: spacing.medium,
		fontSize: 16,
		lineHeight: 1.5,
		color: theme.contentPrimary,
		backgroundColor: theme.surface,
		borderWidth: 1,
		borderStyle: "solid",
		borderColor: theme.border,
		borderRadius: theme.borderRadius,
		outline: "none",
		"::placeholder": {
			color: theme.contentDisabled,
		},
		":disabled": {
			opacity: 0.5,
			cursor: "not-allowed",
		},
		":focus-visible": {
			borderColor: theme.borderStrong,
			boxShadow: `0 0 0 2px ${theme.borderStrong}`,
		},
		":focus-visible[aria-invalid='true']": {
			borderColor: theme.sentimentNegative,
			boxShadow: `0 0 0 3px ${theme.sentimentNegative}`,
		},
	},
	inputSm: {
		paddingTop: spacing.xsmall,
		paddingBottom: spacing.xsmall,
		paddingLeft: spacing.small,
		paddingRight: spacing.small,
		fontSize: 16,
	},
	inputLg: {
		paddingTop: spacing.medium,
		paddingBottom: spacing.medium,
		paddingLeft: spacing.large,
		paddingRight: spacing.large,
		fontSize: 16,
	},

	inputError: {
		borderColor: theme.sentimentNegative,
	},

	error: {
		fontSize: 12,
		lineHeight: 1.4,
		color: theme.sentimentNegative,
	},
});

